"""Tests for irisdonation core operations."""

import pytest

from irisdonation import cli, ops


def _sample():
    records = []
    ops.add_record(records, "food", 12.5, "lunch")
    ops.add_record(records, "travel", 30.0)
    ops.add_record(records, "food", 7.5)
    return records


def test_add_record_appends():
    records = _sample()
    assert len(records) == 3


def test_add_record_returns_record():
    records = []
    record = ops.add_record(records, "misc", 1.0, "x")
    assert record["category"] == "misc"


def test_total_amount():
    assert ops.total_amount(_sample()) == 50.0


def test_filter_by_category_exact():
    assert len(ops.filter_by_category(_sample(), "food")) == 2


def test_top_categories_ranked():
    ranked = ops.top_categories(_sample())
    assert ranked[0] == ("travel", 30.0)


def test_top_categories_limit():
    assert len(ops.top_categories(_sample(), limit=1)) == 1


def test_report_groups_and_sorts_by_total():
    assert ops.report(_sample()) == [
        ("travel", 1, 30.0, None),
        ("food", 2, 20.0, None),
    ]


def test_report_empty():
    assert ops.report([]) == []


def test_report_flags_categories_over_budget():
    assert ops.report(_sample(), {"food": 15.0, "travel": 30.0}) == [
        ("travel", 1, 30.0, False),
        ("food", 2, 20.0, True),
    ]


def test_set_budget_stores_amount():
    budgets = {}
    ops.set_budget(budgets, "food", 15.0)
    assert budgets == {"food": 15.0}


def test_cli_report_output(tmp_path, monkeypatch, capsys):
    monkeypatch.chdir(tmp_path)
    cli.main(["log", "food", "12.5"])
    cli.main(["log", "travel", "30"])
    cli.main(["log", "food", "7.5"])
    capsys.readouterr()

    cli.main(["report"])

    assert capsys.readouterr().out.splitlines() == [
        "travel: 1 records, 30.0",
        "food: 2 records, 20.0",
        "overall: 3 records, 50.0",
    ]


def test_cli_report_empty(tmp_path, monkeypatch, capsys):
    monkeypatch.chdir(tmp_path)

    cli.main(["report"])

    assert capsys.readouterr().out.splitlines() == ["overall: 0 records, 0"]


def test_cli_rejects_blank_category(tmp_path, monkeypatch):
    monkeypatch.chdir(tmp_path)
    with pytest.raises(SystemExit):
        cli.main(["log", "   ", "5"])


def test_cli_rejects_non_finite_amount(tmp_path, monkeypatch):
    monkeypatch.chdir(tmp_path)
    with pytest.raises(SystemExit):
        cli.main(["log", "food", "nan"])


def test_cli_rejects_non_positive_limit(tmp_path, monkeypatch):
    monkeypatch.chdir(tmp_path)
    with pytest.raises(SystemExit):
        cli.main(["top", "--limit", "0"])
